def findWords(board, words):
    class TrieNode:
        def __init__(self):
            self.children = {}
            self.word = None
    root = TrieNode()
    for word in words:
        node = root
        for c in word:
            if c not in node.children: node.children[c] = TrieNode()
            node = node.children[c]
        node.word = word
    res = []
    def dfs(r, c, node):
        char = board[r][c]
        curr = node.children.get(char)
        if not curr: return
        if curr.word:
            res.append(curr.word)
            curr.word = None
        board[r][c] = '#'
        for dr, dc in [(-1,0), (1,0), (0,-1), (0,1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < len(board) and 0 <= nc < len(board[0]):
                dfs(nr, nc, curr)
        board[r][c] = char
    for r in range(len(board)):
        for c in range(len(board[0])):
            dfs(r, c, root)
    return res

